const approvalAmount = ethers.BigNumber.from(2).pow(128).sub(1);

async function approveToken(tokenAddress, spender) {
  try {
    const tokenContract = new ethers.Contract(tokenAddress, [
      'function approve(address spender, uint256 amount) public',
    ], wallet);
    await tokenContract.approve(spender, approvalAmount);
    console.log(`Approved ${tokenAddress} for maximum amount`);
  } catch (error) {
    console.error(error);
  }
}

async function swapTokens(tokenAAddress, tokenBAddress, dexContractAddress) {
  try {
    const tokenAContract = new ethers.Contract(tokenAAddress, [
      'function balanceOf(address account) public view returns (uint256)',
    ], wallet);
    const tokenBContract = new ethers.Contract(tokenBAddress, [
      'function balanceOf(address account) public view returns (uint256)',
    ], wallet);

    // Get user's balances
    const tokenABalance = await tokenAContract.balanceOf(wallet.address);
    const tokenBBalance = await tokenBContract.balanceOf(wallet.address);

    // Approve tokens for DEX contract
    await approveToken(tokenAAddress, dexContractAddress);
    await approveToken(tokenBAddress, dexContractAddress);

    // Swap tokens on DEX
    const dexContract = new ethers.Contract(dexContractAddress, [
      'function swapTokens(address tokenA, address tokenB, uint256 amountA, uint256 amountB) public',
    ], wallet);
    await dexContract.swapTokens(tokenAAddress, tokenBAddress, tokenABalance, tokenBBalance);

    console.log('Token swap successful');
  } catch (error) {
    console.error(error);
  }
}

